+import type { CircuitBreakerOptions, FetchRequest } from "./types.ts";
+
+const defaultFailureStatusCodes = [408, 409, 425, 429, 500, 502, 503, 504];
+
+export interface CircuitConfig {
+  threshold: number;
+  cooldown: number;
+  halfOpenMaxRequests: number;
+  failureStatusCodes: Set<number>;
+}
+
+interface CircuitState {
+  failures: number;
+  state: "closed" | "open" | "half-open";
+  openedAt: number;
+  probes: number;
+}
+
+export interface CircuitReservation {
+  origin: string;
+  config: CircuitConfig;
+  probe: boolean;
+}
+
+export function resolveCircuitConfig(
+  value: boolean | CircuitBreakerOptions | undefined
+): CircuitConfig | undefined {
+  if (!value) {
+    return;
+  }
+  const options = value === true ? {} : value;
+  return {
+    threshold: options.threshold ?? 5,
+    cooldown: options.cooldown ?? 30_000,
+    halfOpenMaxRequests: options.halfOpenMaxRequests ?? 1,
+    failureStatusCodes: new Set(
+      options.failureStatusCodes ?? defaultFailureStatusCodes
+    ),
+  };
+}
+
+export function getRequestOrigin(request: FetchRequest): string | undefined {
+  const url = request instanceof Request ? request.url : String(request);
+  try {
+    return new URL(url).origin;
+  } catch {
+    return;
+  }
+}
+
+export class CircuitBreaker {
+  private states = new Map<string, CircuitState>();
+
+  acquire(origin: string, config: CircuitConfig): CircuitReservation {
+    const state = this.states.get(origin) || {
+      failures: 0,
+      state: "closed" as const,
+      openedAt: 0,
+      probes: 0,
+    };
+    this.states.set(origin, state);
+
+    if (state.state === "open") {
+      if (Date.now() - state.openedAt < config.cooldown) {
+        throw new Error("Circuit breaker is open");
+      }
+      state.state = "half-open";
+      state.probes = 0;
+    }
+    if (state.state === "half-open") {
+      if (state.probes >= config.halfOpenMaxRequests) {
+        throw new Error("Circuit breaker is open");
+      }
+      state.probes++;
+      return { origin, config, probe: true };
+    }
+    return { origin, config, probe: false };
+  }
+
+  complete(reservation: CircuitReservation, outcome: "success" | "failure" | "neutral") {
+    const state = this.states.get(reservation.origin);
+    if (!state) {
+      return;
+    }
+    if (reservation.probe) {
+      state.probes--;
+    }
+    if (outcome === "failure") {
+      if (state.state === "half-open") {
+        state.state = "open";
+        state.openedAt = Date.now();
+        state.probes = 0;
